  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const RING_COUNT = 4;
  7→const SPIRAL_ARMS = 3;
  8→const SPIRAL_PARTICLES = 16;
  9→const OUTER_PARTICLE_COUNT = 14;
 10→
 11→/** Parse "#5f92ff" → { r, g, b } */
 12→const parseHex = (hex) => ({
 13→    r: parseInt(hex.slice(1, 3), 16),
 14→    g: parseInt(hex.slice(3, 5), 16),
 15→    b: parseInt(hex.slice(5, 7), 16),
 16→});
 17→
 18→/** Lerp between two RGB colors */
 19→const lerpRgb = (a, b, t) => ({
 20→    r: Math.round(a.r + (b.r - a.r) * t),
 21→    g: Math.round(a.g + (b.g - a.g) * t),
 22→    b: Math.round(a.b + (b.b - a.b) * t),
 23→});
 24→
 25→const WHITE = { r: 255, g: 255, b: 255 };
 26→
 27→const WormholeLayer = React.memo(({ layerProps, wormholes, zoom }) => {
 28→    const animRef = useRef({ time: 0 });
 29→    const shapeRef = useRef(null);
 30→    const rafRef = useRef(null);
 31→
 32→    // Always bright
 33→    const opacity = zoom < 0.15 ? 1.0
 34→        : zoom < 1.0 ? 1.0 - (zoom - 0.15) * 0.2
 35→        : 0.83;
 36→
 37→    // Pre-compute vortex data with colors and stable phase offsets
 38→    const vortexData = useMemo(() => {
 39→        if (!Array.isArray(wormholes)) return [];
 40→        return wormholes.map((wh, i) => {
 41→            const color = STAR_COLORS[i % STAR_COLORS.length];
 42→            const rgb = parseHex(color);
 43→            const hashVal = wh.post_a ? parseInt(wh.post_a.slice(0, 8), 16) : i * 12345;
 44→            return {
 45→                ...wh,
 46→                color,
 47→                rgb,
 48→                phaseA: (hashVal % 1000) / 1000 * TWO_PI,
 49→                phaseB: ((hashVal * 7) % 1000) / 1000 * TWO_PI,
 50→            };
 51→        });
 52→    }, [wormholes]);
 53→
 54→    const animate = useCallback(() => {
 55→        animRef.current.time = performance.now();
 56→        if (shapeRef.current) {
 57→            shapeRef.current.getLayer()?.batchDraw();
 58→        }
 59→        rafRef.current = requestAnimationFrame(animate);
 60→    }, []);
 61→
 62→    useEffect(() => {
 63→        if (vortexData.length === 0) return;
 64→        rafRef.current = requestAnimationFrame(animate);
 65→        return () => {
 66→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 67→        };
 68→    }, [animate, vortexData.length]);
 69→
 70→    if (vortexData.length === 0) return null;
 71→
 72→    const drawVortex = (ctx, x, y, rgb, time, phaseOffset, radius) => {
 73→        const breathe = 1.0 + 0.25 * Math.sin(time * 0.001 + phaseOffset);
 74→        const r = radius * breathe;
 75→
 76→        // Large pulsing outer halo — makes it unmissable
 77→        const pulseScale = 1.0 + 0.3 * Math.sin(time * 0.0015 + phaseOffset);
 78→        const haloR = r * 4.0 * pulseScale;
 79→        const haloGrad = ctx.createRadialGradient(x, y, 0, x, y, haloR);
 80→        haloGrad.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.25 * opacity})`);
 81→        haloGrad.addColorStop(0.3, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.12 * opacity})`);
 82→        haloGrad.addColorStop(0.6, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.04 * opacity})`);
 83→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
 84→        ctx.beginPath();
 85→        ctx.arc(x, y, haloR, 0, TWO_PI);
 86→        ctx.fillStyle = haloGrad;
 87→        ctx.fill();
 88→
 89→        // Inner bright glow
 90→        const innerGlow = ctx.createRadialGradient(x, y, 0, x, y, r * 1.8);
 91→        innerGlow.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.45 * opacity})`);
 92→        innerGlow.addColorStop(0.4, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.2 * opacity})`);
 93→        innerGlow.addColorStop(1, 'rgba(0,0,0,0)');
 94→        ctx.beginPath();
 95→        ctx.arc(x, y, r * 1.8, 0, TWO_PI);
 96→        ctx.fillStyle = innerGlow;
 97→        ctx.fill();
 98→
 99→        // Dark center void (the "hole")
100→        const voidGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.4);
101→        voidGrad.addColorStop(0, `rgba(0,0,0,${0.85 * opacity})`);
102→        voidGrad.addColorStop(0.6, `rgba(0,0,0,${0.4 * opacity})`);
103→        voidGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.beginPath();
105→        ctx.arc(x, y, r * 0.4, 0, TWO_PI);
106→        ctx.fillStyle = voidGrad;
107→        ctx.fill();
108→
