export const useUpdateJournalPrivacyMutation = (session) =>{
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: (data) => updatePrivacy(session?.access_token, data),
        onMutate: async(data) => {
            await queryClient.cancelQueries(['userJournals', session?.user?.id])
            const previousData = queryClient.getQueryData(['userJournals', session?.user?.id])

            const journalId = data.get('journalId')
            const privacy = data.get('privacy');

            // console.log(privacy)

            queryClient.setQueryData(['userJournals', session?.user?.id], (old) => {
                if(!old) return old;

                return{
                    ...old,
                    pages: old.pages.map((page) => ({
                        ...page,
                        data: page.data.map((journal) => {
                            if(journal.id !== journalId) return journal;

                            return{
                                ...journal,
                                privacy: privacy
                            }
                        })
                    }))
                }
            })
            console.log(previousData)
            return {previousData};

        },
        onError: (err, data, context) =>{
            queryClient.setQueryData(['userJournals', session?.user?.id], context.previousData)
        },
        onSuccess: (data) => console.log(data),
        retry: 1,
    })
}
export const useUpdateCollectionPrivacyMutation = (session) => {
    const queryClient= useQueryClient();
    return useMutation({
        mutationFn: (data) => updateCollectionPrivacy(data, session?.access_token),
        onMutate: async(data) =>{
            const userId = data.get('userId')
            const collectionId = data.get('collectionId')
            await queryClient.cancelQueries(['getCollections', userId])

            const previousData = queryClient.getQueryData(['getCollections', userId])
            const isPublic = data.get('isPublic');

            queryClient.setQueryData(['getCollections', userId], (old) => {
                if(!old) return old;

                return{
                    ...old,
                    pages: old.pages.map((page) =>({
                        ...page,
                        data: page.data.map((collection) => {
                            if(collection.id !== collectionId) return collection;

                            return {
                                ...collection,
                                is_public: isPublic
                            }
                        })
                    }))
                }
            })
            return {previousData};
        },
        onError: (err, data, context) =>{
            queryClient.setQueryData(['getCollections', session?.user?.id], context.previousData)
        },
        retry: 1,
        onSucces: (data) => console.log(data)
    })
}

