.universeContainer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(ellipse at center, #0a0e1a 0%, #000000 100%);
    touch-action: none;
    cursor: grab;
    z-index: 1000;
    overflow: hidden;
}

.universeContainer.grabbing {
    cursor: grabbing;
}

.backButton {
    position: absolute;
    top: 16px;
    left: 16px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.backButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.backButton svg {
    width: 18px;
    height: 18px;
    fill: #e0e0e0;
}

.distanceTracker {
    position: absolute;
    bottom: 184px;
    left: 16px;
    z-index: 1010;
    padding: 6px 12px;
    background: rgba(255, 255, 255, 0.04);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.35);
    font-size: 12px;
    font-family: monospace;
    pointer-events: none;
}

.loadingOverlay {
    position: absolute;
    inset: 0;
    z-index: 1040;
    display: flex;
