    background: #0a0e1a;
}

.galaxyPreviewHeading {
    font-size: 15px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
    margin-top: 10px;
    text-align: center;
}

.galaxyPreviewBio {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 8px;
    text-align: center;
    display: -webkit-box;
    -webkit-line-clamp: 3;
