    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewVisitBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

/* Minimap */
.minimap {
    position: absolute;
    bottom: 16px;
    left: 16px;
    z-index: 1010;
    width: 160px;
    height: 160px;
    border-radius: 10px;
    cursor: crosshair;
    pointer-events: auto;
    transition: opacity 0.2s;
}

.minimap:hover {
    opacity: 0.95;
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
