}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .distanceTracker {
        bottom: auto;
        top: 12px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 300px;
    }
}

