export const STAR_COLORS = ['#5f92ff', '#ff5fa2', '#5fffb0', '#ffd75f', '#b05fff', '#ff8a5f'];

export const MIN_UNIVERSE_ZOOM = 0.02;
export const MAX_UNIVERSE_ZOOM = 5;
export const HOME_SCALE = 0.8;
export const GUEST_SCALE = 0.05;

export const simpleHash = (str) => {
    let h = 0;
    for (let i = 0; i < str.length; i++) {
        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
    }
    return Math.abs(h);
};

export const userHomeCoords = (userId) => {
    if (!userId) return { x: 0, y: 0 };
    const mid = Math.floor(userId.length / 2);
    const xHash = simpleHash(userId.slice(0, mid));
    const yHash = simpleHash(userId.slice(mid));

