    cursor: crosshair;
    pointer-events: auto;
    transition: opacity 0.2s;
}

.minimap:hover {
    opacity: 0.95;
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
    );
    animation: warpPulse 1.8s ease-in-out forwards;
}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

