  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape, Text } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→
  7→const parseHex = (hex) => ({
  8→    r: parseInt(hex.slice(1, 3), 16),
  9→    g: parseInt(hex.slice(3, 5), 16),
 10→    b: parseInt(hex.slice(5, 7), 16),
 11→});
 12→
 13→const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId }) => {
 14→    const animRef = useRef({ time: 0 });
 15→    const shapeRef = useRef(null);
 16→    const rafRef = useRef(null);
 17→
 18→    const linkData = useMemo(() => {
 19→        if (!Array.isArray(constellations) || constellations.length === 0) return [];
 20→        return constellations.map((link, i) => {
 21→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 22→            const rgb = parseHex(colorHex);
 23→            const isPending = link.status === 'pending';
 24→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
 25→            return { ...link, rgb, colorHex, isPending, isOwnPending };
 26→        });
 27→    }, [constellations, chainColors, userId]);
 28→
 29→    const animate = useCallback(() => {
 30→        animRef.current.time = performance.now();
 31→        if (shapeRef.current) {
 32→            shapeRef.current.getLayer()?.batchDraw();
 33→        }
 34→        rafRef.current = requestAnimationFrame(animate);
 35→    }, []);
 36→
 37→    useEffect(() => {
 38→        if (linkData.length === 0) return;
 39→        rafRef.current = requestAnimationFrame(animate);
 40→        return () => {
 41→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 42→        };
 43→    }, [animate, linkData.length]);
 44→
 45→    if (linkData.length === 0) return null;
 46→
 47→    return (
 48→        <Layer {...layerProps} listening={false}>
 49→            <Shape
 50→                ref={shapeRef}
 51→                sceneFunc={(ctx) => {
 52→                    const time = animRef.current.time;
 53→
 54→                    for (const link of linkData) {
 55→                        const posA = computedStarPositions.get(link.star_id_a);
 56→                        const posB = computedStarPositions.get(link.star_id_b);
 57→                        if (!posA || !posB) continue;
 58→
 59→                        const { rgb } = link;
 60→                        const ax = posA.x;
 61→                        const ay = posA.y;
 62→                        const bx = posB.x;
 63→                        const by = posB.y;
 64→
 65→                        if (link.isPending) {
 66→                            // Only show pending links for current user
 67→                            if (!link.isOwnPending) continue;
 68→
 69→                            // Dim dashed line
 70→                            ctx.save();
 71→                            ctx.setLineDash([6, 10]);
 72→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
 73→                            ctx.lineWidth = 1;
 74→                            ctx.beginPath();
 75→                            ctx.moveTo(ax, ay);
 76→                            ctx.lineTo(bx, by);
 77→                            ctx.stroke();
 78→                            ctx.setLineDash([]);
 79→                            ctx.restore();
 80→                            continue;
 81→                        }
 82→
 83→                        // Accepted link: outer glow
 84→                        ctx.save();
 85→                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.08)`;
 86→                        ctx.lineWidth = 6;
 87→                        ctx.beginPath();
 88→                        ctx.moveTo(ax, ay);
 89→                        ctx.lineTo(bx, by);
 90→                        ctx.stroke();
 91→
 92→                        // Inner line
 93→                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.35)`;
 94→                        ctx.lineWidth = 1.5;
 95→                        ctx.beginPath();
